1	import { describe, it, expect, vi, beforeEach } from "vitest";
2	import { screen, fireEvent } from "@testing-library/react";
3	import { renderWithProviders } from "./helpers";
4	import { VariableRow } from "@/features/assumptions/VariableRow";
5	import { AssumptionProvider, useAssumptions } from "@/features/assumptions/AssumptionContext";
6	import type { Market } from "@/lib/api/types";
7	
8	// ---------------------------------------------------------------------------
9	// Mocks
10	// ---------------------------------------------------------------------------
11	
12	const mockMutate = vi.fn();
13	
14	vi.mock("@/features/session/context", async () => {
15	  const actual = await vi.importActual<typeof import("@/features/session/context")>(
16	    "@/features/session/context",
17	  );
18	  return {
19	    ...actual,
20	    useSession: vi.fn(),
21	  };
22	});
23	
24	vi.mock("@/lib/query/hooks", () => ({
25	  useMarket: vi.fn(),
26	  useProbabilityEdit: vi.fn(),
27	}));
28	
29	import { useSession } from "@/features/session/context";
30	import { useMarket, useProbabilityEdit } from "@/lib/query/hooks";
31	
32	const mockUseSession = vi.mocked(useSession);
33	const mockUseMarket = vi.mocked(useMarket);
